+// isZombieState returns true if the agent state or hook bead indicates a zombie.
+func isZombieState(agentState, hookBead string) bool {
+	if hookBead != "" {
+		return true
+	}
+	return agentState == "working" || agentState == "running" || agentState == "spawning"
